import base64, os
content = base64.b64decode("""""").decode('utf-8')
output_path = r"C:\\instagram cap generation\\templates\\index.html"
os.makedirs(os.path.dirname(output_path), exist_ok=True)
with open(output_path, 'w', encoding='utf-8') as f:
    f.write(content)
checks = [
    "CapGen v3.1",
    "border-radius:999px",
    ".tpl-btn.active{background:var(--teal);border-color:var(--teal)",
    ".pill.selected{background:var(--teal);border-color:var(--teal)",
    ".toggle-btn.active{background:var(--teal);border-color:var(--teal)",
    ".trend-cat.active{background:var(--teal);border-color:var(--teal)",
    ".platform-btn.active{background:var(--teal);border-color:var(--teal)",
]
print("SUCCESS! Verification:")
all_ok = True
for c in checks:
    ok = c in content
    print(f"  {'OK' if ok else 'MISSING'}: {c[:60]}")
    if not ok: all_ok = False
print("\n" + ("ALL GOOD - push to GitHub!" if all_ok else "ISSUES FOUND"))
